package main.java.org.example;import com.gamestudio.tictactoe.Board;import com.gamestudio.tictactoe.Player;import java.util.Scanner;public class TicTacToe {    private Player player1;    private Player player2;    private Player currentPlayer;    private Board board;    public TicTacToe() {        player1 = new Player('X');        player2 = new Player('O');        currentPlayer = player1;        board = new Board();    }    public void start() {        Scanner scanner = new Scanner(System.in);        boolean playAgain = true;        while (playAgain) {            board.clear();            currentPlayer = player1;            System.out.println("--- TicTacToe Game Started ---");            board.print();            while (!hasWinner() && !board.isFull()) {                System.out.println("Current Player: " + currentPlayer.getMarker());                System.out.print("row (0-2): ");                int row = scanner.nextInt();                System.out.print("column (0-2): ");                int col = scanner.nextInt();                if (board.place(row, col, currentPlayer.getMarker())) {                    board.print();                    if (hasWinner()) {                        System.out.println("Game over! Player " + currentPlayer.getMarker() + " has won!");                    } else if (board.isFull()) {                        System.out.println("Game over! It is a draw!");                    } else {                        switchCurrentPlayer();                    }                } else {                    System.out.println("This move is invalid or the cell is already taken! Try again.");                }            }            System.out.print("Start a new game? (yes/no): ");            String answer = scanner.next();            playAgain = answer.equalsIgnoreCase("yes") || answer.equalsIgnoreCase("y");        }        System.out.println("Thanks for playing!");        scanner.close();    }    private void switchCurrentPlayer() {        currentPlayer = currentPlayer == player1 ? player2 : player1;    }    private boolean hasWinner() {        char[][] cells = board.getCells();        char marker = currentPlayer.getMarker();        for (int i = 0; i < 3; i++) {            if (cells[i][0] == marker && cells[i][1] == marker && cells[i][2] == marker) {                return true;            }            if (cells[0][i] == marker && cells[1][i] == marker && cells[2][i] == marker) {                return true;            }        }        return (cells[0][0] == marker && cells[1][1] == marker && cells[2][2] == marker)                || (cells[0][2] == marker && cells[1][1] == marker && cells[2][0] == marker);    }    public static void main(String[] args) {        TicTacToe game = new TicTacToe();        game.start();    }}